return new Promise(function (resolve, reject) {
  const url = '{{startUrl}}' + 'wp-json/wc-automation-helper/log-request-response/?url_path=currency-rates?base-currency={{defaultCurr}}';
  const username = '{{woo_user}}';
  const password = '{{woo_pass}}';
  let headers = new Headers();
  headers.set('Content-Type', 'application/json');
  headers.set('Authorization', 'Basic ' + btoa(username + ":" + password));
  fetch(url, {method:'GET', headers: headers, credentials: 'omit'})
  .then(function(response) {
    if (response.ok) {
      resolve(response.json())
    } else {
      resolve([])
    } 
  })
  })

let rates = {{rates}};
let currency = "{{curr}}";
let rate;
let boolean = false;
let n = 0
while (boolean === false && rates.response.currencyRate.length > n) {
    if (rates.response.currencyRate[n].quoteCurrency != currency) {
        n++
    } else {
        rate = rates.response.currencyRate[n].conversionRate
        boolean = true
    }
}
return rate
